```typescript
import { HttpStatus, INestApplication, Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';
import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
import * as request from 'supertest';

import { AuthGuard } from '@modules/auth/guards/auth.guard';
import { RolesGuard } from '@modules/auth/guards/roles.guard';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { JiraInstallService } from '@modules/jira/jira-install.service';
import { JiraController } from '@modules/jira/jira.controller';

const mockJiraInstallService = {
	initiateConnect: jest.fn(),
	handleCallback: jest.fn(),
	disconnect: jest.fn(),
};

const mockConfigService = { get: jest.fn().mockReturnValue('http://localhost:3000') };

const mockUser = {
	user_id: 'user-uuid-1',
	company_id: 'company-uuid-1',
	roles: ['admin'],
};

describe('JiraController (e2e)', () => {
	let app: INestApplication;

	beforeAll(async () => {
		const moduleFixture: TestingModule = await Test.createTestingModule({
			controllers: [JiraController],
			providers: [
				{ provide: JiraInstallService, useValue: mockJiraInstallService },
				{ provide: EnvConfigService, useValue: mockConfigService },
			],
		})
			.overrideGuard(AuthGuard)
			.useValue({
				canActivate: (ctx: unknown) => {
					const req = (
						ctx as { switchToHttp: () => { getRequest: () => unknown } }
					)
						.switchToHttp()
						.getRequest() as Record<string, unknown>;
					req['user'] = mockUser;
					return true;
				},
			})
			.overrideGuard(RolesGuard)
			.useValue({ canActivate: () => true })
			.compile();

		app = moduleFixture.createNestApplication<NestFastifyApplication>(
			new FastifyAdapter(),
		);
		app.setGlobalPrefix('api');
		await app.init();
		await app.getHttpAdapter().getInstance().ready();

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'debug').mockImplementation(jest.fn());
	});

	afterAll(async () => {
		await app.close();
	});

	afterEach(() => jest.clearAllMocks());

	describe('POST /api/integrations/jira/connect', () => {
		it('should return 200 with OAuth URL', async () => {
			mockJiraInstallService.initiateConnect.mockResolvedValue(
				'https://auth.atlassian.com/authorize?client_id=test',
			);

			const res = await request(app.getHttpServer())
				.post('/api/integrations/jira/connect')
				.expect(HttpStatus.OK);

			expect(res.body).toEqual({
				url: 'https://auth.atlassian.com/authorize?client_id=test',
			});
		});

		it('should return 500 when service throws', async () => {
			mockJiraInstallService.initiateConnect.mockRejectedValue(new Error('cache down'));

			await request(app.getHttpServer())
				.post('/api/integrations/jira/connect')
				.expect(HttpStatus.INTERNAL_SERVER_ERROR);
		});
	});

	describe('GET /api/integrations/jira/callback', () => {
		it('should redirect to frontend with connected=jira on success', async () => {
			mockJiraInstallService.handleCallback.mockResolvedValue({ _id: 'install-1' });

			const res = await request(app.getHttpServer())
				.get('/api/integrations/jira/callback?code=auth-code&state=some-state')
				.expect(HttpStatus.FOUND);

			expect(res.headers['location']).toContain('connected=jira');
		});

		it('should redirect to frontend with error on failure', async () => {
			mockJiraInstallService.handleCallback.mockRejectedValue(
				new Error('invalid state'),
			);

			const res = await request(app.getHttpServer())
				.get('/api/integrations/jira/callback?code=bad-code&state=bad-state')
				.expect(HttpStatus.FOUND);

			expect(res.headers['location']).toContain('error=jira_connect_failed');
		});
	});

	describe('DELETE /api/integrations/jira/installations/:id', () => {
		it('should return 204 on successful disconnect', async () => {
			mockJiraInstallService.disconnect.mockResolvedValue(undefined);

			await request(app.getHttpServer())
				.delete('/api/integrations/jira/installations/install-uuid-1')
				.expect(HttpStatus.NO_CONTENT);

			expect(mockJiraInstallService.disconnect).toHaveBeenCalledWith({
				installationDbId: 'install-uuid-1',
				companyId: mockUser.company_id,
			});
		});

		it('should return 500 when disconnect throws', async () => {
			mockJiraInstallService.disconnect.mockRejectedValue(new Error('db error'));

			await request(app.getHttpServer())
				.delete('/api/integrations/jira/installations/install-uuid-1')
				.expect(HttpStatus.INTERNAL_SERVER_ERROR);
		});
	});
});
```

